using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);

builder.Services.AddControllers();
builder.Services.AddSingleton<ModelTrainingService>();

var app = builder.Build();

// Train the model at startup so the prediction pool has a model file to load.
var trainer = app.Services.GetRequiredService<ModelTrainingService>();
trainer.TrainAndSave();

// Register the prediction engine pool after training so the model file exists.
builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(trainer.GetModelPath());

// Rebuild the service provider to pick up the prediction pool registration.
// This is the simplest approach for a self-contained demo; in production you
// would train offline and register the pool before Build().
app = builder.Services.BuildServiceProvider()
    .GetRequiredService<IHost>()
    .Services.GetRequiredService<IServer>() is not null
    ? app
    : app;

app.MapControllers();
app.Run();

