using Microsoft.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);

builder.Services.AddControllers();
builder.Services.AddSingleton<ModelTrainingService>();

// Train the model at startup before the pool is needed.
var dataPath = builder.Configuration.GetValue<string>("ML:DataPath")
    ?? Path.Combine(builder.Environment.ContentRootPath, "Data", "tickets.csv");
var modelPath = builder.Configuration.GetValue<string>("ML:ModelPath")
    ?? Path.Combine(builder.Environment.ContentRootPath, "Data", "model.zip");

TrainModel(dataPath, modelPath);

builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(modelPath);

var app = builder.Build();
app.MapControllers();
app.Run();

static void TrainModel(string dataPath, string modelPath)
{
    var mlContext = new MLContext(seed: 42);

    var data = mlContext.Data.LoadFromTextFile<TicketInput>(
        dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

    var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

    var pipeline = mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketInput.Subject))
        .Append(mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketInput.Description)))
        .Append(mlContext.Transforms.Concatenate("Features", "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketInput.Priority)))
        .Append(mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketInput.Category)))
        .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy("Label", "Features"))
        .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

    Console.WriteLine("Training model...");
    var model = pipeline.Fit(split.TrainSet);

    var predictions = model.Transform(split.TestSet);
    var metrics = mlContext.MulticlassClassification.Evaluate(predictions, "Label");

    Console.WriteLine("=== Model Evaluation Metrics ===");
    Console.WriteLine($"MacroAccuracy:    {metrics.MacroAccuracy:F4}");
    Console.WriteLine($"MicroAccuracy:    {metrics.MicroAccuracy:F4}");
    Console.WriteLine($"LogLoss:          {metrics.LogLoss:F4}");
    Console.WriteLine($"LogLossReduction: {metrics.LogLossReduction:F4}");

    mlContext.Model.Save(model, data.Schema, modelPath);
    Console.WriteLine($"Model saved to {modelPath}");
}

